public partial class ClientesService
{
    private async Task<IEnumerable<ClientesResponseAll>> GetDataAllAsync(MsiSqlConnection oCnn, int max, string where, List<SqlParameter>? parameters, string tenantKey, CancellationToken cancellationToken)
    {
        if (oCnn == null || oCnn?.InnerConnection?.State == ConnectionState.Closed)
        {
            return[];
        }

        try
        {
            // Usar o reader para obter os dados
            return await reader.ListarAsync(oCnn!, max, tenantKey, where.Replace(TSql.Where, ""), parameters, "", cancellationToken);
        }
        catch (Exception)
        {
            return[];
        }
    }

    public async Task<ResultApi<IEnumerable<NomeID>>> GetListN(int max, Filters.FilterClientes? filtro, string tenantKey, CancellationToken token = default)
    {
        // Tracking: 20250606-0
        ThrowIfDisposed();
        if (!(await Uris.ValidaUriAsync(tenantKey, _entityService)))
        {
            throw new Exception("Clientes: TenantApp inválida");
        }

        var filtroResult = filtro == null ? null : servicesFilter.WFiltroClientes(filtro!);
        string where = filtroResult?.where ?? string.Empty;
        List<SqlParameter>? parameters = filtroResult?.parametros ?? [];
        using var scope = await _connectionService.CreateConnectionScopeAsync(tenantKey);
        using var oCnn = scope.Connection;
        if (oCnn == null)
        {
            return ResultApi<IEnumerable<NomeID>>.Fail("Conexão nula.", 503);
        }

        var keyCache = await reader.ReadStringAuditorAsync(tenantKey, oCnn, _cache);
        var filterHash = DevourerOne.ComputeFilterHash(where, parameters);
        var cacheKey = $"{tenantKey}-Clientes-{max}-{filterHash}-GetListN-{keyCache}";
        var entryOptions = new HybridCacheEntryOptions
        {
            Expiration = TimeSpan.FromSeconds(BaseConsts.PMaxSecondsCacheId),
            LocalCacheExpiration = TimeSpan.FromSeconds(BaseConsts.PMaxSecondsCacheId)
        };
        try
        {
            var result = await _cache.GetOrCreateAsync(cacheKey, async cancel => await GetDataListNAsync(max, tenantKey, where, parameters, cancel), entryOptions, cancellationToken: token) ?? [];
            return ResultApi<IEnumerable<NomeID>>.Ok(result);
        }
        catch (Exception ex)
        {
            _logger.Error(ex, "Clientes: GetListN failed");
            return ResultApi<IEnumerable<NomeID>>.Fail(ex.Message, 500);
        }
    }

    private async Task<IEnumerable<NomeID>> GetDataListNAsync(int max, string tenantKey, string where, List<SqlParameter>? parameters, CancellationToken token)
    {
        var result = new List<NomeID>(max);
        var lista = await reader.ListarNAsync(max, tenantKey, where, parameters, DBClientesDicInfo.CampoNome);
        if (lista == null || !lista.Any())
        {
            return result;
        }

        foreach (var item in lista)
        {
            if (token.IsCancellationRequested)
                continue;
            if (item?.FNome != null)
            {
                result.Add(new NomeID { Nome = item.FNome, ID = item.ID });
            }
        }

        return result;
    }

    public async Task<ResultApi<IEnumerable<ClientesResponseAll>>> GetAll(int max, string tenantKey, CancellationToken token = default)
    {
        ThrowIfDisposed();
        max = Math.Min(Math.Max(max, 1), BaseConsts.PMaxItens);
        if (!(await Uris.ValidaUriAsync(tenantKey, _entityService)))
        {
            throw new Exception("Clientes: TenantApp inválida");
        }

        var entryOptions = new HybridCacheEntryOptions
        {
            Expiration = TimeSpan.FromMinutes(BaseConsts.PMaxMinutesCache),
            LocalCacheExpiration = TimeSpan.FromMinutes(BaseConsts.PMaxMinutesCache)
        };
        using var scope = await _connectionService.CreateConnectionScopeAsync(tenantKey);
        using var oCnn = scope.Connection;
        var keyCache = await reader.ReadStringAuditorAsync(tenantKey, oCnn, _cache);
        var cacheKey = $"{tenantKey}-Clientes-Filter-{max}-{keyCache}";
        try
        {
            var result = await _cache.GetOrCreateAsync(cacheKey, async cancel => await GetDataAllAsync2(oCnn!, max, string.Empty, [], tenantKey, cancel), entryOptions, cancellationToken: token);
            return ResultApi<IEnumerable<ClientesResponseAll>>.Ok(result);
        }
        catch (Exception ex)
        {
            _logger.Error(ex, "Clientes: GetAll failed for tenantKey = {0}", tenantKey);
            return ResultApi<IEnumerable<ClientesResponseAll>>.Fail(ex.Message, 500);
        }
    }

    private async Task<IEnumerable<ClientesResponseAll>> GetDataAllAsync2(MsiSqlConnection oCnn, int max, string where, List<SqlParameter>? parameters, string tenantKey, CancellationToken token)
    {
        if (oCnn == null || oCnn?.InnerConnection?.State == ConnectionState.Closed)
        {
            throw new DatabaseConnectionException();
        }

        var result = await reader.ListarAsync(oCnn!, max, tenantKey, where, parameters, string.Empty, token);
        return result;
    }
}